DNA = ""
temp = list(DNA)
leng = len(temp)
for i in range (0,leng):
    if temp[i] == "T":
        temp[i] = "U"

print (temp)

DNA = "".join(temp)

print(DNA)


# 使用 string.replace 。 注意string本身是不可变的
DNA = ""

RNA = DNA.replace('T','U')

print(RNA)


